import{_ as e,o as s,c as o,B as i}from"./chunks/framework.BalCpBef.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{"layout":false},"headers":[],"relativePath":"process.md","filePath":"process.md"}'),n={name:"process.md"};function l(a,t,r,c,g,p){return s(),o("div",null,[...t[0]||(t[0]=[i(`<div class="content-hero"><div class="content-hero-inner"><div class="content-hero-label">Process</div><h1 class="content-hero-title">How I Work</h1></div></div><div style="padding:1rem 2rem 0;max-width:900px;margin:0 auto;"><img src="/images/process-011-e1437083324870.png" alt="Design process overview" style="width:100%;"></div><div class="content-body"><div class="process-steps"><pre><code>&lt;div class=&quot;process-step&quot;&gt;
  &lt;div class=&quot;process-step-num&quot;&gt;01 — Define&lt;/div&gt;
  &lt;div&gt;
    &lt;h2 class=&quot;process-step-title&quot;&gt;Define&lt;/h2&gt;
    &lt;div class=&quot;process-step-sub&quot;&gt;Discover and empathize.&lt;/div&gt;
    &lt;p class=&quot;process-step-body&quot;&gt;Defining a problem requires research, and I like to tackle this in stages. I start by collecting feedback from the team, reading user reviews of previous gen products, and checking out user feedback on the competition. This tips me off to products I should test first-hand, users to talk to, or studies to be performed for greater insight. Throughout the process, I share findings through decks, competitive analyses, and user personas to align the team in a common direction.&lt;/p&gt;
    &lt;div class=&quot;process-step-images&quot;&gt;
      &lt;div&gt;
        &lt;img :src=&quot;&#39;/images/orange-personsa-techtrailblazer.png&#39;&quot; alt=&quot;User persona: Tech Trailblazer&quot; /&gt;
      &lt;/div&gt;
      &lt;div&gt;
        &lt;img :src=&quot;&#39;/images/orange-personsa-digitalpassive.png&#39;&quot; alt=&quot;User persona: Digital Passive&quot; /&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;process-step&quot;&gt;
  &lt;div class=&quot;process-step-num&quot;&gt;02 — Ideate&lt;/div&gt;
  &lt;div&gt;
    &lt;h2 class=&quot;process-step-title&quot;&gt;Ideate&lt;/h2&gt;
    &lt;div class=&quot;process-step-sub&quot;&gt;Outline the solution.&lt;/div&gt;
    &lt;p class=&quot;process-step-body&quot;&gt;Ideating brings a rough vision of the solution. Post-its and white boards are my favorite places to sketch and refine user workflows and information architecture. I involve key stakeholders in this process to generate the best ideas.&lt;/p&gt;
    &lt;div class=&quot;gallery-full&quot;&gt;
      &lt;img :src=&quot;&#39;/images/whiteboard2.png&#39;&quot; alt=&quot;Whiteboarding session&quot; /&gt;
      &lt;p class=&quot;img-caption&quot;&gt;Whiteboarding&lt;/p&gt;
    &lt;/div&gt;
    &lt;div class=&quot;gallery-full&quot;&gt;
      &lt;img :src=&quot;&#39;/images/mind-mapping-e1437152706209.png&#39;&quot; alt=&quot;User and flow mapping&quot; /&gt;
      &lt;p class=&quot;img-caption&quot;&gt;User and flow mapping&lt;/p&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;process-step&quot;&gt;
  &lt;div class=&quot;process-step-num&quot;&gt;03 — Prototype&lt;/div&gt;
  &lt;div&gt;
    &lt;h2 class=&quot;process-step-title&quot;&gt;Prototype&lt;/h2&gt;
    &lt;div class=&quot;process-step-sub&quot;&gt;Bring the idea to life.&lt;/div&gt;
    &lt;p class=&quot;process-step-body&quot;&gt;Ideas go from fuzzy to clear in the prototyping stage. Pen and paper is my favorite place to begin. Once the direction is clear, I move to a design program like Sketch to bring the design to a higher fidelity. If the feature is new or hard to explain in a linear flow, I create an interactive prototype using InVision. Throughout this process, I work closely with a writer on interface copy.&lt;/p&gt;
    &lt;div class=&quot;gallery-full&quot;&gt;
      &lt;img :src=&quot;&#39;/images/dm-design-iterations2.png&#39;&quot; alt=&quot;Iterations of the Device Manager overview screen&quot; /&gt;
      &lt;p class=&quot;img-caption&quot;&gt;Iterations of the Device Manager overview screen&lt;/p&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;process-step&quot;&gt;
  &lt;div class=&quot;process-step-num&quot;&gt;04 — Test&lt;/div&gt;
  &lt;div&gt;
    &lt;h2 class=&quot;process-step-title&quot;&gt;Test&lt;/h2&gt;
    &lt;div class=&quot;process-step-sub&quot;&gt;Do users &#39;get it&#39;?&lt;/div&gt;
    &lt;p class=&quot;process-step-body&quot;&gt;As soon as there is something tangible to show, I seek out representative users for feedback. Usability tests with targeted end users is the gold standard, but the minimum is a hallway test with a person not close to the project. The testing leads to new iterations and greater confidence in the final design.&lt;/p&gt;
  &lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;process-step&quot;&gt;
  &lt;div class=&quot;process-step-num&quot;&gt;05 — Build&lt;/div&gt;
  &lt;div&gt;
    &lt;h2 class=&quot;process-step-title&quot;&gt;Build&lt;/h2&gt;
    &lt;div class=&quot;process-step-sub&quot;&gt;Dot the i&#39;s and cross the t&#39;s.&lt;/div&gt;
    &lt;p class=&quot;process-step-body&quot;&gt;The build stage is where the rubber meets the road. I create software specifications for workflows and UI components that make it clear for developers. I also stay in close contact throughout the development process to QA components and troubleshoot any issues that come up.&lt;/p&gt;
    &lt;div class=&quot;gallery-full&quot;&gt;
      &lt;img :src=&quot;&#39;/images/text-box-specs.png&#39;&quot; alt=&quot;UI component specification&quot; /&gt;
      &lt;p class=&quot;img-caption&quot;&gt;UI component specification&lt;/p&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;process-step&quot;&gt;
  &lt;div class=&quot;process-step-num&quot;&gt;06 — Analyze&lt;/div&gt;
  &lt;div&gt;
    &lt;h2 class=&quot;process-step-title&quot;&gt;Analyze&lt;/h2&gt;
    &lt;div class=&quot;process-step-sub&quot;&gt;Influence the next generation.&lt;/div&gt;
    &lt;p class=&quot;process-step-body&quot;&gt;Post launch is a great time to take stock of how things went. Product reviews, star ratings, customer support calls, and feedback from the press are all great indicators of how successful a product is. These provide insights for the next product generation.&lt;/p&gt;
  &lt;/div&gt;
&lt;/div&gt;
</code></pre></div></div>`,3)])])}const q=e(n,[["render",l]]);export{d as __pageData,q as default};
